import React, { createContext, useState, useContext, useEffect } from 'react';
import { getSocket } from '../socket';

const ChatContext = createContext();

export const useChat = () => useContext(ChatContext);

export const ChatProvider = ({ children }) => {
  const [onlineUsers, setOnlineUsers] = useState([]);
  const [selectedUser, setSelectedUser] = useState(null);
  const [messages, setMessages] = useState({});
  const [typing, setTyping] = useState({});

  useEffect(() => {
    const socket = getSocket();
    if (!socket) return;

    socket.on('online_users', (users) => {
      setOnlineUsers(users);
    });

    socket.on('receive_message', (data) => {
      const { from, message, timestamp } = data;
      setMessages(prev => ({
        ...prev,
        [from]: [...(prev[from] || []), { from, text: message, timestamp, received: true }]
      }));
    });

    socket.on('user_typing', ({ from }) => {
      setTyping(prev => ({ ...prev, [from]: true }));
    });

    socket.on('user_stop_typing', ({ from }) => {
      setTyping(prev => ({ ...prev, [from]: false }));
    });

    return () => {
      socket.off('online_users');
      socket.off('receive_message');
      socket.off('user_typing');
      socket.off('user_stop_typing');
    };
  }, []);

  const sendMessage = (to, message, fromUserId) => {
    const socket = getSocket();
    if (socket) {
      socket.emit('send_message', { to, message, from: fromUserId });
      setMessages(prev => ({
        ...prev,
        [to]: [...(prev[to] || []), { from: fromUserId, text: message, timestamp: new Date(), received: false }]
      }));
    }
  };

  const sendTyping = (to, from) => {
    const socket = getSocket();
    if (socket) {
      socket.emit('typing', { to, from });
    }
  };

  const sendStopTyping = (to, from) => {
    const socket = getSocket();
    if (socket) {
      socket.emit('stop_typing', { to, from });
    }
  };

  return (
    <ChatContext.Provider value={{
      onlineUsers,
      selectedUser,
      setSelectedUser,
      messages,
      typing,
      sendMessage,
      sendTyping,
      sendStopTyping
    }}>
      {children}
    </ChatContext.Provider>
  );
};

export default ChatContext;
